+package com.vmware.vropsqa.test;
+
+import com.fasterxml.jackson.databind.JsonNode;
+import com.vmware.vropsqa.test.util.AdapterUtils;
+import com.vmware.vropsqa.test.util.AdapterUtils.AdapterSummary;
+import com.vmware.vropsqa.test.util.AdapterUtils.MonitoringStateResponse;
+import org.apache.http.impl.client.CloseableHttpClient;
+import org.apache.logging.log4j.LogManager;
+import org.apache.logging.log4j.Logger;
+import org.testng.Assert;
+import org.testng.annotations.Test;
+
+import java.util.ArrayList;
+import java.util.LinkedHashMap;
+import java.util.List;
+import java.util.Map;
+import java.util.Set;
+
+/**
+ * Runs before other password-management tests: lists vROps adapter instances and stops
+ * collection for selected adapter kinds to reduce load during VCF password workflows.
+ */
+public class AdapterMonitoringStopTest extends BasePasswordTest {
+
+    private static final Logger logger = LogManager.getLogger(AdapterMonitoringStopTest.class);
+
+    private static final Set<String> TARGET_ADAPTER_KIND_KEYS = Set.of(
+            "NSXT",
+            "NSXTAdapter",
+            "VMWARE",
+            "VcfAdapter",
+            "VirtualAndPhysicalSANAdapter");
+
+    @Test
+    public void testStopAdapterCollection() throws Exception {
+        token = fetchVropsToken();
+
+        logger.info("===== AdapterMonitoringStopTest: listing adapters =====");
+
+        JsonNode root;
+        try (CloseableHttpClient httpClient = createHttpClient()) {
+            root = AdapterUtils.fetchAdapters(httpClient, opsHostUrl, token, objectMapper);
+        }
+        logger.info("List adapters response status: 200");
+
+        JsonNode instances = AdapterUtils.resolveAdapterInstancesArray(root);
+        Assert.assertNotNull(instances, "Could not find adapter instances array in response");
+
+        List<AdapterSummary> allAdapters = new ArrayList<>();
+        List<AdapterSummary> matched = new ArrayList<>();
+
+        for (JsonNode node : instances) {
+            AdapterSummary s = AdapterSummary.from(node);
+            allAdapters.add(s);
+            if (s.adapterKindKey != null && TARGET_ADAPTER_KIND_KEYS.contains(s.adapterKindKey)) {
+                matched.add(s);
+            }
+        }
+
+        logger.info("Total adapter instances reported: {}", allAdapters.size());
+        for (AdapterSummary s : allAdapters) {
+            logger.info("  [ALL] id={} adapterKindKey={} name={} description={}",
+                    s.id, s.adapterKindKey, s.name, s.description);
+        }
+
+        logger.info("Target adapter kinds: {}", TARGET_ADAPTER_KIND_KEYS);
+        logger.info("Matched instances (will attempt stop): {}", matched.size());
+        for (AdapterSummary s : matched) {
+            logger.info("  [MATCH] id={} adapterKindKey={} name={}", s.id, s.adapterKindKey, s.name);
+        }
+
+        if (matched.isEmpty()) {
+            logger.info("No adapter instances for kinds {} — nothing to stop.", TARGET_ADAPTER_KIND_KEYS);
+            return;
+        }
+
+        List<String> stoppedOk = new ArrayList<>();
+        Map<String, String> failures = new LinkedHashMap<>();
+
+        try (CloseableHttpClient httpClient = createHttpClient()) {
+            for (AdapterSummary s : matched) {
+                if (s.id == null || s.id.isEmpty()) {
+                    String msg = "missing id for adapterKindKey=" + s.adapterKindKey;
+                    logger.error("Skip stop: {}", msg);
+                    failures.put(s.adapterKindKey + "(no-id)", msg);
+                    continue;
+                }
+                String stopUrl = String.format(
+                        "https://%s/suite-api/api/adapters/%s/monitoringstate/stop?_no_links=true",
+                        opsHostUrl, s.id);
+                logger.info("PUT {} (stop collection) adapterKindKey={} id={}", stopUrl, s.adapterKindKey, s.id);
+                MonitoringStateResponse stopResult =
+                        AdapterUtils.stopAdapterCollection(httpClient, opsHostUrl, token, s.id);
+                if (stopResult.isSuccess()) {
+                    stoppedOk.add(s.adapterKindKey + ":" + s.id);
+                    logger.info("  STOP OK (200) adapterKindKey={} id={}", s.adapterKindKey, s.id);
+                } else {
+                    String detail = "HTTP " + stopResult.statusCode + " body="
+                            + AdapterUtils.truncate(stopResult.body, 2000);
+                    failures.put(s.adapterKindKey + ":" + s.id, detail);
+                    logger.error("  STOP FAILED adapterKindKey={} id={} {}", s.adapterKindKey, s.id, detail);
+                }
+            }
+        }
+
+        logger.info("===== AdapterMonitoringStopTest summary =====");
+        logger.info("Stopped successfully (200): {}", stoppedOk.size());
+        for (String e : stoppedOk) {
+            logger.info("  [STOPPED] {}", e);
+        }
+        if (!failures.isEmpty()) {
+            logger.error("Failures: {}", failures.size());
+            failures.forEach((k, v) -> logger.error("  [FAIL] {} -> {}", k, v));
+        }
+        Assert.assertTrue(failures.isEmpty(),
+                "Expected HTTP 200 for every stop call; failures=" + failures);
+
+        logger.info("===== AdapterMonitoringStopTest completed =====");
+    }
+}

