+ */
+package com.vmware.vropsqa.test.util;
+
+import com.fasterxml.jackson.databind.JsonNode;
+import com.fasterxml.jackson.databind.ObjectMapper;
+import org.apache.http.client.methods.CloseableHttpResponse;
+import org.apache.http.client.methods.HttpGet;
+import org.apache.http.client.methods.HttpPut;
+import org.apache.http.impl.client.CloseableHttpClient;
+import org.apache.http.util.EntityUtils;
+
+import java.io.IOException;
+
+/**
+ * vROps suite-api helpers for adapter instances and adapter monitoring (collection) state.
+ * <p>
+ * Stop collection: {@code PUT .../api/adapters/{id}/monitoringstate/stop?_no_links=true}<br>
+ * Start collection: {@code PUT .../api/adapters/{id}/monitoringstate/start?_no_links=true}<br>
+ * Success is indicated by HTTP 200.
+ */
+public final class AdapterUtils {
+
+    private static final String LIST_ADAPTERS_URL = "https://%s/suite-api/api/adapters";
+    private static final String MONITORING_STATE_URL =
+            "https://%s/suite-api/api/adapters/%s/monitoringstate/%s?_no_links=true";
+
+    private static final String HEADER_AUTHORIZATION = "Authorization";
+    private static final String HEADER_X_OPS_API_UNSUPPORTED = "X-Ops-API-use-unsupported";
+    private static final String HEADER_X_VREALIZEOPS_UNSUPPORTED = "x-vrealizeops-api-use-unsupported";
+    private static final String HEADER_ACCEPT = "Accept";
+
+    private AdapterUtils() {
+    }
+
+    /**
+     * GET /suite-api/api/adapters — returns parsed JSON root when status is 200.
+     *
+     * @throws IllegalStateException if the response status is not 200
+     */
+    public static JsonNode fetchAdapters(CloseableHttpClient httpClient, String hostName, String token,
+                                         ObjectMapper objectMapper) throws IOException {
+        String listUrl = String.format(LIST_ADAPTERS_URL, hostName);
+        HttpGet httpGet = createAdaptersListGet(listUrl, token);
+        try (CloseableHttpResponse response = httpClient.execute(httpGet)) {
+            int status = response.getStatusLine().getStatusCode();
+            String body = response.getEntity() != null ? EntityUtils.toString(response.getEntity()) : "";
+            if (status != 200) {
+                throw new IllegalStateException(
+                        "GET /suite-api/api/adapters failed: HTTP " + status + " body=" + truncate(body, 2000));
+            }
+            return objectMapper.readTree(body);
+        }
+    }
+
+    /**
+     * Stops collection for the adapter instance. HTTP 200 indicates success.
+     */
+    public static MonitoringStateResponse stopAdapterCollection(CloseableHttpClient httpClient, String hostName,
+                                                                  String token, String adapterId) throws IOException {
+        return putMonitoringState(httpClient, hostName, token, adapterId, "stop");
+    }
+
+    /**
+     * Starts collection for the adapter instance. HTTP 200 indicates success.
+     */
+    public static MonitoringStateResponse startAdapterCollection(CloseableHttpClient httpClient, String hostName,
+                                                                   String token, String adapterId) throws IOException {
+        return putMonitoringState(httpClient, hostName, token, adapterId, "start");
+    }
+
+    /** Result of a monitoring start/stop PUT; {@link #statusCode} 200 means the operation succeeded. */
+    public static final class MonitoringStateResponse {
+        public final int statusCode;
+        public final String body;
+
+        public MonitoringStateResponse(int statusCode, String body) {
+            this.statusCode = statusCode;
+            this.body = body != null ? body : "";
+        }
+
+        public boolean isSuccess() {
+            return statusCode == 200;
+        }
+    }
+
+    private static MonitoringStateResponse putMonitoringState(CloseableHttpClient httpClient, String hostName,
+                                                              String token, String adapterId, String stopOrStart)
+            throws IOException {
+        String url = String.format(MONITORING_STATE_URL, hostName, adapterId, stopOrStart);
+        HttpPut put = createMonitoringStatePut(url, token);
+        try (CloseableHttpResponse response = httpClient.execute(put)) {
+            int code = response.getStatusLine().getStatusCode();
+            String body = response.getEntity() != null ? EntityUtils.toString(response.getEntity()) : "";
+            return new MonitoringStateResponse(code, body);
+        }
+    }
+
+    public static JsonNode resolveAdapterInstancesArray(JsonNode root) {
+        if (root == null || root.isNull()) {
+            return null;
+        }
+        if (root.isArray()) {
+            return root;
+        }
+        String[] keys = {
+                "adapterInstancesInfoDto",
+                "adapterInstances",
+                "adapterInstanceDTOs",
+                "instances",
+                "results"};
+        for (String key : keys) {
+            JsonNode arr = root.get(key);
+            if (arr != null && arr.isArray()) {
+                return arr;
+            }
+        }
+        return null;
+    }
+
+    public static String truncate(String s, int max) {
+        if (s == null) {
+            return "";
+        }
+        if (s.length() <= max) {
+            return s;
+        }
+        return s.substring(0, max) + "...";
+    }
+
+    private static HttpGet createAdaptersListGet(String url, String token) {
+        HttpGet httpGet = new HttpGet(url);
+        httpGet.setHeader(HEADER_AUTHORIZATION, "OpsToken " + token);
+        httpGet.setHeader(HEADER_X_OPS_API_UNSUPPORTED, "true");
+        httpGet.setHeader(HEADER_X_VREALIZEOPS_UNSUPPORTED, "true");
+        httpGet.setHeader(HEADER_ACCEPT, "*/*");
+        return httpGet;
+    }
+
+    private static HttpPut createMonitoringStatePut(String url, String token) {
+        HttpPut httpPut = new HttpPut(url);
+        httpPut.setHeader(HEADER_AUTHORIZATION, "OpsToken " + token);
+        httpPut.setHeader(HEADER_X_OPS_API_UNSUPPORTED, "true");
+        httpPut.setHeader(HEADER_X_VREALIZEOPS_UNSUPPORTED, "true");
+        httpPut.setHeader(HEADER_ACCEPT, "*/*");
+        return httpPut;
+    }
+
+    /** Summary of one adapter instance from the list-adapters JSON. */
+    public static final class AdapterSummary {
+        public final String id;
+        public final String adapterKindKey;
+        public final String name;
+        public final String description;
+
+        public AdapterSummary(String id, String adapterKindKey, String name, String description) {
+            this.id = id;
+            this.adapterKindKey = adapterKindKey;
+            this.name = name;
+            this.description = description;
+        }
+
+        public static AdapterSummary from(JsonNode node) {
+            String id = textOrNull(node, "id");
+            if (id == null || id.isEmpty()) {
+                id = textOrNull(node, "uuid");
+            }
+            JsonNode resourceKey = node.path("resourceKey");
+            boolean hasResourceKey = resourceKey != null && !resourceKey.isMissingNode() && !resourceKey.isNull();
+
+            String kind = firstNonEmpty(
+                    textOrNull(node, "adapterKindKey"),
+                    hasResourceKey ? textOrNull(resourceKey, "adapterKindKey") : null,
+                    textOrNull(node, "adapterKind"),
+                    hasResourceKey ? textOrNull(resourceKey, "adapterKind") : null);
+            if (kind != null) {
+                kind = kind.trim();
+            }
+
+            String name = firstNonEmpty(
+                    textOrNull(node, "name"),
+                    hasResourceKey ? textOrNull(resourceKey, "name") : null);
+            String desc = textOrNull(node, "description");
+            return new AdapterSummary(id, kind, name, desc);
+        }
+
+        private static String firstNonEmpty(String... candidates) {
+            if (candidates == null) {
+                return null;
+            }
+            for (String c : candidates) {
+                if (c != null && !c.isEmpty()) {
+                    return c;
+                }
+            }
+            return null;
+        }
+
+        private static String textOrNull(JsonNode node, String field) {
+            if (!node.has(field) || node.get(field).isNull()) {
+                return null;
+            }
+            String t = node.get(field).asText("");
+            if (t == null) {
+                return null;
+            }
+            t = t.trim();
+            return t.isEmpty() ? null : t;
+        }
+    }
+}
